-- ===== SET 1: Level 1, Questions 1-10 =====
INSERT INTO questions (practice_set_id, question_order, question_text, answer_option_1, answer_option_2, answer_option_3, answer_option_4, correct_answer_number) VALUES
(1, 1, 'התלמיד הלך בבוקר לבית הספר. לאן הלך התלמיד?', 'לבית', 'לפארק', 'לבית הספר', 'לחנות', 3),
(1, 2, 'אמא מבשלת אוכל במטבח. מה אמא עושה?', 'קוראת ספר', 'ישנה', 'מבשלת אוכל', 'יוצאת מהבית', 3),
(1, 3, 'החברים נסעו בשבת לים. מתי הם נסעו?', 'ביום ראשון', 'בלילה', 'בשבת', 'בבוקר', 3),
(1, 4, 'הילד שיחק כדורגל עם חברים. עם מי הילד שיחק?', 'עם מורה', 'לבד', 'עם אח', 'עם חברים', 4),
(1, 5, 'האיש קנה אוכל בחנות. מה האיש קנה?', 'בגדים', 'צעצועים', 'ספרים', 'אוכל', 4),
(1, 6, 'התלמידים לומדים בכיתה. איפה התלמידים לומדים?', 'בפארק', 'בבית', 'ברחוב', 'בכיתה', 4),
(1, 7, 'התלמיד קורא ספר. מה התלמיד עושה?', 'כותב', 'משחק', 'קורא ספר', 'רץ', 3),
(1, 8, 'אנשים אוכלים ארוחת בוקר בבוקר. מתי אוכלים ארוחת בוקר?', 'בערב', 'בלילה', 'בצהריים', 'בבוקר', 4),
(1, 9, 'הילדים משחקים בפארק. איפה הילדים משחקים?', 'בבית', 'בבית ספר', 'בפארק', 'בחנות', 3),
(1, 10, 'הרופא עובד בבית חולים. איפה הרופא עובד?', 'בבית ספר', 'בחנות', 'במשרד', 'בבית חולים', 4);

-- ===== SET 2: Level 1, Questions 11-20 =====
INSERT INTO questions (practice_set_id, question_order, question_text, answer_option_1, answer_option_2, answer_option_3, answer_option_4, correct_answer_number) VALUES
(2, 1, 'הילד שותה מים. מה הילד שותה?', 'חלב', 'מיץ', 'קפה', 'מים', 4),
(2, 2, 'האיש ישן בלילה. מתי האיש ישן?', 'בבוקר', 'בצהריים', 'בערב', 'בלילה', 4),
(2, 3, 'הספר נמצא במדף. איפה נמצא הספר?', 'בתיק', 'על הרצפה', 'בשולחן', 'במדף', 4),
(2, 4, 'התלמיד לומד בשיעור. מה התלמיד עושה בשיעור?', 'משחק', 'ישן', 'רץ', 'לומד', 4),
(2, 5, 'הילד הולך לישון בלילה. מתי הילד הולך לישון?', 'בבוקר', 'בצהריים', 'בערב', 'בלילה', 4),
(2, 6, 'הילדים משחקים עם חברים. עם מי הילדים משחקים?', 'עם מורים', 'לבד', 'עם הורים', 'עם חברים', 4),
(2, 7, 'האנשים גרים בבית. איפה האנשים גרים?', 'ברחוב', 'בעבודה', 'בבית ספר', 'בבית', 4),
(2, 8, 'הילד קורא ספר חדש. מה הילד עושה?', 'אוכל', 'שותה', 'כותב', 'קורא ספר', 4),
(2, 9, 'התלמיד הולך לבית הספר בבוקר. מתי התלמיד הולך לבית הספר?', 'בלילה', 'בערב', 'בצהריים', 'בבוקר', 4),
(2, 10, 'כשחם הילד שותה מים. מה הילד עושה כשחם?', 'לובש מעיל', 'אוכל', 'ישן', 'שותה מים', 4);

-- ===== SET 3: Level 2, Questions 1-10 =====
INSERT INTO questions (practice_set_id, question_order, question_text, answer_option_1, answer_option_2, answer_option_3, answer_option_4, correct_answer_number) VALUES
(3, 1, 'התלמיד הלך לבית הספר אחרי שאכל ארוחת בוקר. מתי הלך התלמיד לבית הספר?', 'לפני שאכל', 'בזמן שאכל', 'אחרי שאכל', 'בלילה', 3),
(3, 2, 'אמא קנתה ירקות ופירות בשוק. מה אמא קנתה?', 'בגדים', 'ספרים', 'צעצועים', 'ירקות ופירות', 4),
(3, 3, 'הילד שיחק כדורגל עם חברים אחרי בית הספר. מתי שיחק הילד כדורגל?', 'לפני בית הספר', 'בבוקר', 'אחרי בית הספר', 'בלילה', 3),
(3, 4, 'האיש נסע באוטובוס לעבודה כי לא היה לו רכב. למה האיש נסע באוטובוס?', 'כי הוא אוהב אוטובוסים', 'כי הוא רצה לטייל', 'כי היה מאוחר', 'כי לא היה לו רכב', 4),
(3, 5, 'התלמיד למד לבחינה במשך שעתיים בבית. כמה זמן התלמיד למד?', 'שעה', 'שלוש שעות', 'שעתיים', 'יום שלם', 3),
(3, 6, 'הילדים אכלו גלידה אחרי שהם שיחקו בפארק. מה עשו הילדים אחרי המשחק?', 'חזרו הביתה', 'שתו מים', 'אכלו גלידה', 'למדו', 3),
(3, 7, 'המורה הסביר את החומר כדי שהתלמידים יבינו יותר טוב. למה המורה הסביר את החומר?', 'כדי לסיים מהר', 'כדי ללכת הביתה', 'כדי לבדוק תלמידים', 'כדי שהתלמידים יבינו', 4),
(3, 8, 'האיש קם מוקדם כדי להגיע לעבודה בזמן. למה האיש קם מוקדם?', 'כי הוא עייף', 'כי הוא אוהב בוקר', 'כי אין לו עבודה', 'כדי להגיע לעבודה בזמן', 4),
(3, 9, 'הילדה קראה ספר מעניין במשך כל הערב. מה הילדה עשתה בערב?', 'שיחקה', 'למדה', 'קראה ספר', 'ישנה', 3),
(3, 10, 'החברים נפגשו בבית כדי ללמוד יחד לבחינה. למה החברים נפגשו?', 'כדי לשחק', 'כדי לאכול', 'כדי לטייל', 'כדי ללמוד לבחינה', 4);

-- ===== SET 4: Level 2, Questions 11-20 =====
INSERT INTO questions (practice_set_id, question_order, question_text, answer_option_1, answer_option_2, answer_option_3, answer_option_4, correct_answer_number) VALUES
(4, 1, 'האיש קנה כרטיס לרכבת ונסע לעיר אחרת. איך האיש נסע לעיר?', 'באוטובוס', 'ברכב', 'במטוס', 'ברכבת', 4),
(4, 2, 'התלמיד לא הבין את השאלה ולכן ביקש עזרה מהמורה. מה עשה התלמיד כשלא הבין?', 'הלך הביתה', 'כתב תשובה', 'ביקש עזרה', 'ישן', 3),
(4, 3, 'הילד סידר את החדר לפני שהחברים הגיעו. מתי הילד סידר את החדר?', 'אחרי שהחברים הגיעו', 'בזמן שהם היו שם', 'בלילה', 'לפני שהחברים הגיעו', 4),
(4, 4, 'האישה עבדה קשה כדי להצליח בעבודה החדשה. למה האישה עבדה קשה?', 'כדי לנוח', 'כדי לעזוב', 'כדי ללמוד', 'כדי להצליח בעבודה', 4),
(4, 5, 'התלמידים יצאו להפסקה אחרי השיעור הארוך. מתי יצאו התלמידים להפסקה?', 'לפני השיעור', 'באמצע השיעור', 'בלילה', 'אחרי השיעור', 4),
(4, 6, 'האיש שתה מים כי היה לו חם מאוד. למה האיש שתה מים?', 'כי היה רעב', 'כי רצה לישון', 'כי היה עייף', 'כי היה לו חם', 4),
(4, 7, 'הילדה כתבה במחברת כדי לזכור את החומר. למה הילדה כתבה?', 'כדי לצייר', 'כדי לדבר', 'כדי לשחק', 'כדי לזכור את החומר', 4),
(4, 8, 'המשפחה נסעה לטיול בצפון ביום שבת. לאן המשפחה נסעה?', 'לים', 'לעיר', 'לצפון', 'לבית ספר', 3),
(4, 9, 'התלמיד חזר הביתה אחרי שסיים את הלימודים. מתי התלמיד חזר הביתה?', 'לפני הלימודים', 'באמצע היום', 'בלילה', 'אחרי הלימודים', 4),
(4, 10, 'הילדים צפו בטלוויזיה אחרי שסיימו את שיעורי הבית. מה עשו הילדים אחרי שיעורי הבית?', 'יצאו מהבית', 'אכלו', 'ישנו', 'צפו בטלוויזיה', 4);

-- ===== SET 5: Level 3, Questions 1-10 =====
INSERT INTO questions (practice_set_id, question_order, question_text, answer_option_1, answer_option_2, answer_option_3, answer_option_4, correct_answer_number) VALUES
(5, 1, 'התלמיד החליט לשנות את שיטת הלמידה לאחר שלא הצליח במבחן הקודם. למה התלמיד שינה את שיטת הלמידה?', 'כי רצה לנסות משהו חדש', 'כי המורה ביקש', 'כי חברים המליצו', 'כי לא הצליח במבחן הקודם', 4),
(5, 2, 'האישה דחתה את הפגישה למרות שהייתה חשובה, בגלל מצב חירום בבית. למה האישה דחתה את הפגישה?', 'כי לא רצתה להגיע', 'כי שכחה', 'כי הייתה עייפה', 'בגלל מצב חירום בבית', 4),
(5, 3, 'למרות שהייתה עייפה, הילדה המשיכה ללמוד כדי להתכונן למבחן החשוב. למה הילדה המשיכה ללמוד?', 'כי לא הייתה עייפה', 'כי רצתה לשחק', 'כי המורה דרש', 'כדי להתכונן למבחן', 4),
(5, 4, 'האיש בדק את כל האפשרויות לפני שקיבל החלטה סופית. מה האיש עשה לפני שקיבל החלטה?', 'בחר מיד', 'שאל חברים', 'התייעץ עם המשפחה', 'בדק את כל האפשרויות', 4),
(5, 5, 'התלמידים התקשו להבין את הנושא החדש, ולכן ביקשו הסבר נוסף מהמורה. למה התלמידים ביקשו הסבר נוסף?', 'כי היה להם משעמם', 'כי רצו לסיים מהר', 'כי לא הקשיבו', 'כי התקשו להבין את הנושא', 4),
(5, 6, 'למרות מזג האוויר הקשה, העובדים המשיכו בעבודתם כרגיל. מה עשו העובדים למרות מזג האוויר?', 'חזרו הביתה', 'הפסיקו לעבוד', 'חיכו', 'המשיכו לעבוד כרגיל', 4),
(5, 7, 'הילד התלבט בין שתי אפשרויות לפני שבחר במה שנראה לו נכון יותר. מה הילד עשה לפני שבחר?', 'בחר מיד', 'ביקש עזרה', 'עזב את העניין', 'התלבט בין אפשרויות', 4),
(5, 8, 'האישה קראה את המאמר כמה פעמים כדי להבין את הרעיון המרכזי. למה האישה קראה את המאמר כמה פעמים?', 'כי אהבה לקרוא', 'כי לא היה לה זמן', 'כי רצתה לכתוב', 'כדי להבין את הרעיון המרכזי', 4),
(5, 9, 'האיש לא הסכים להצעה למרות שהייתה משתלמת מבחינה כלכלית. מה ניתן להבין מהמשפט?', 'האיש קיבל את ההצעה', 'ההצעה לא הייתה טובה', 'האיש לא הבין', 'האיש בחר לא להסכים למרות היתרון', 4),
(5, 10, 'התלמיד שיפר את הציון לאחר שהקדיש יותר זמן ללמידה. מה גרם לשיפור בציון?', 'עזרה מחברים', 'מבחן קל', 'מזל', 'השקעה בלמידה', 4);

-- ===== SET 6: Level 3, Questions 11-20 =====
INSERT INTO questions (practice_set_id, question_order, question_text, answer_option_1, answer_option_2, answer_option_3, answer_option_4, correct_answer_number) VALUES
(6, 1, 'האישה הגיעה למסקנה לאחר שבחנה את הנתונים לעומק. איך האישה הגיעה למסקנה?', 'לפי תחושה', 'בעזרת חברים', 'במקרה', 'לאחר בחינת הנתונים', 4),
(6, 2, 'למרות שהדרך הייתה ארוכה ומאתגרת, הקבוצה המשיכה עד שהגיעה ליעד. מה הקבוצה עשתה?', 'עצרה באמצע', 'חזרה לאחור', 'התלוננה', 'המשיכה עד היעד', 4),
(6, 3, 'האיש בחר לא להגיב מיד, אלא לחשוב לפני שענה. מה ניתן להבין על האיש?', 'הוא ממהר', 'הוא לא מבין', 'הוא לא עונה', 'הוא חושב לפני תגובה', 4),
(6, 4, 'התלמידים הצליחו במשימה לאחר שעבדו יחד ושיתפו פעולה. למה הצליחו התלמידים?', 'כי עבדו לבד', 'כי המשימה הייתה קלה', 'כי לא ניסו', 'כי שיתפו פעולה', 4),
(6, 5, 'הילדה הרגישה יותר בטוחה לאחר שהתאמנה כמה פעמים. מה גרם לתחושה הטובה יותר?', 'עזרה מהמורה', 'מזל', 'זמן פנוי', 'אימון חוזר', 4),
(6, 6, 'האיש הבין את הטעות רק לאחר שקיבל הסבר נוסף. מתי האיש הבין את הטעות?', 'מיד', 'לפני ההסבר', 'תוך כדי עבודה', 'לאחר הסבר נוסף', 4),
(6, 7, 'התלמיד בחר להתמקד בנושא אחד כדי להבין אותו לעומק. למה התלמיד התמקד בנושא אחד?', 'כי לא היה זמן', 'כי היה קל', 'כי לא רצה ללמוד', 'כדי להבין לעומק', 4),
(6, 8, 'האישה החליטה לפעול לפי דעתה האישית, למרות ההמלצות. מה ניתן להבין על האישה?', 'היא מקשיבה תמיד לאחרים', 'היא לא מבינה', 'היא לא מקבלת החלטות', 'היא פועלת לפי דעתה', 4),
(6, 9, 'האיש שינה את דעתו לאחר שמע מידע חדש בנושא. למה האיש שינה את דעתו?', 'כי התעייף', 'כי לא רצה להחליט', 'כי שכח', 'בגלל מידע חדש', 4),
(6, 10, 'התלמידים התקדמו במהירות לאחר שהבינו את שיטת העבודה. מה עזר לתלמידים להתקדם?', 'מזל', 'זמן', 'עזרה מהמורה בלבד', 'הבנת שיטת העבודה', 4);

-- ===== SET 7: Level 4 Passages 1-5 (10 questions) =====
INSERT INTO questions (practice_set_id, question_order, question_text, answer_option_1, answer_option_2, answer_option_3, answer_option_4, correct_answer_number) VALUES
(7, 1, 'הרכבת נחשבת לאמצעי תחבורה יעיל במיוחד בערים גדולות. היא מאפשרת לאנשים להגיע לעבודה במהירות וללא פקקים. עם זאת, כאשר יש תקלה במערכת, עיכוב קטן יכול לגרום לשיבושים רבים ולפגוע בלוח הזמנים של נוסעים רבים.
למה אנשים מעדיפים להשתמש ברכבת?', 'כי היא זולה יותר', 'כי יש בה יותר מקום', 'כי היא מהירה ואין בה פקקים', 'כי היא פועלת תמיד', 3),
(7, 2, 'הרכבת נחשבת לאמצעי תחבורה יעיל במיוחד בערים גדולות. היא מאפשרת לאנשים להגיע לעבודה במהירות וללא פקקים. עם זאת, כאשר יש תקלה במערכת, עיכוב קטן יכול לגרום לשיבושים רבים ולפגוע בלוח הזמנים של נוסעים רבים.
מה עלול לקרות כאשר יש תקלה?', 'הרכבת נעצרת לנצח', 'הנוסעים יורדים מיד', 'אין שינוי', 'נגרמים עיכובים ושיבושים', 4),
(7, 3, 'בשנים האחרונות עלו מחירי הדיור במדינות רבות. הסיבה לכך היא שילוב של ביקוש גבוה ועצה נמוך. כאשר יש יותר אנשים שרוצים לקנות דירות מאשר דירות זמינות, המחירים עולים באופן טבעי.
למה מחירי הדיור עולים?', 'כי אנשים לא רוצים לקנות דירות', 'כי יש הרבה דירות', 'כי יש ביקוש גבוה ועצה נמוך', 'כי אין אנשים', 3),
